css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0a0014; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 76px; border-bottom: 1px solid rgba(236,72,153,0.15); position: sticky; top: 0; background: rgba(10,0,20,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 24px; font-weight: 900; } .logo span { color: #ec4899; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; transition: color 0.2s; } .links a:hover { color: white; }
.hire-btn { padding: 12px 24px; border-radius: 12px; border: 1px solid rgba(236,72,153,0.5); background: rgba(236,72,153,0.1); color: #ec4899; font-weight: 700; cursor: pointer; transition: all 0.2s; } .hire-btn:hover { background: rgba(236,72,153,0.2); }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 76px); }
.role { display: inline-block; color: #ec4899; font-size: 13px; font-weight: 700; letter-spacing: 3px; margin-bottom: 20px; }
h1 { font-size: 64px; font-weight: 900; line-height: 1.05; letter-spacing: -2px; margin-bottom: 20px; }
.hero-text p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 32px; max-width: 440px; }
.hero-btns { display: flex; gap: 14px; }
.btn-primary { padding: 16px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #ec4899, #f97316); color: white; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-secondary { padding: 16px 28px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.avatar-card { background: rgba(255,255,255,0.05); border: 1px solid rgba(236,72,153,0.2); border-radius: 24px; padding: 28px; display: flex; gap: 20px; align-items: center; margin-bottom: 16px; }
.avatar-img { width: 80px; height: 80px; border-radius: 20px; background: linear-gradient(135deg, #ec4899, #f97316); display: flex; align-items: center; justify-content: center; font-size: 36px; flex-shrink: 0; }
.avatar-info strong { display: block; font-size: 18px; font-weight: 800; margin-bottom: 4px; } .avatar-info span { color: #9ca3af; font-size: 13px; display: block; margin-bottom: 12px; }
.tools { display: flex; gap: 8px; } .tools span { padding: 4px 10px; border-radius: 6px; background: rgba(236,72,153,0.1); color: #f9a8d4; font-size: 12px; font-weight: 600; }
.stat-chips { display: flex; flex-direction: column; gap: 10px; }
.chip { padding: 12px 18px; border-radius: 14px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); font-size: 14px; font-weight: 600; color: #e2e8f0; }
.work { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.06); }
.work-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 36px; }
.work-header h2 { font-size: 42px; font-weight: 800; }
.work-filters { display: flex; gap: 8px; }
.wf { padding: 10px 20px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .wf.active { background: #ec4899; border-color: #ec4899; color: white; }
.work-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }
.work-card { border-radius: 20px; overflow: hidden; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); transition: all 0.3s; cursor: pointer; } .work-card:hover { transform: translateY(-6px); border-color: rgba(236,72,153,0.3); box-shadow: 0 20px 40px rgba(0,0,0,0.3); }
.wc-img { height: 180px; display: flex; align-items: center; justify-content: center; font-size: 56px; }
.wc-info { padding: 20px; } .wc-cat { font-size: 11px; font-weight: 700; color: #ec4899; letter-spacing: 2px; display: block; margin-bottom: 8px; } .wc-info h3 { font-size: 17px; font-weight: 700; margin-bottom: 6px; } .wc-info p { color: #6b7280; font-size: 13px; line-height: 1.6; }

js:
function filter(cat, btn) {
  document.querySelectorAll('.wf').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.work-card').forEach(card => {
    if (cat === 'all' || card.dataset.cat === cat) {
      card.style.display = 'block';
      card.style.animation = 'fadeIn 0.3s ease';
    } else {
      card.style.display = 'none';
    }
  });
}
document.head.insertAdjacentHTML('beforeend', '<style>@keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}</style>');
